from typing import List, Dict
import requests
from bs4 import BeautifulSoup
import pandas as pd
import time
from urllib.parse import urljoin

class JobScraper:
    def __init__(self, base_url: str, pages: int = 5):
        self.base_url = base_url
        self.pages = pages
        self.session = requests.Session()
        self.session.headers.update({
            'User-Agent': 'JobScraper/1.0 (contact@example.com)'
        })

    def scrape_all(self) -> List[Dict]:
        all_jobs = []

        for page in range(1, self.pages + 1):
            print(f'🔄 Scraping page {page}/{self.pages}')
            url = f'{self.base_url}?page={page}'

            try:
                resp = self.session.get(url, timeout=10)
                soup = BeautifulSoup(resp.content, 'lxml')

                jobs = self._parse_jobs(soup)
                all_jobs.extend(jobs)

                time.sleep(2)  # Be nice

            except Exception as e:
                print(f'⚠️  Page {page} failed: {e}')

        return all_jobs

    def _parse_jobs(self, soup) -> List[Dict]:
        jobs = []
        cards = soup.select('.job-listing, .job-card, article.job')

        for card in cards:
            job = {
                'title': self._safe_text(card, 'h2 a, h3 a, .job-title'),
                'company': self._safe_text(card, '.company, .employer'),
                'location': self._safe_text(card, '.location, .city'),
                'salary': self._safe_text(card, '.salary'),
                'url': self._safe_attr(card, 'a', 'href')
            }
            if job['title'] != 'N/A':
                jobs.append(job)

        return jobs

    def _safe_text(self, elem, selector):
        found = elem.select_one(selector)
        return found.get_text(strip=True) if found else 'N/A'

    def _safe_attr(self, elem, tag, attr):
        found = elem.find(tag)
        if found and found.get(attr):
            return urljoin(self.base_url, found[attr])
        return 'N/A'

if __name__ == '__main__':
    scraper = JobScraper('https://jobs.example.com', pages=3)
    jobs = scraper.scrape_all()

    df = pd.DataFrame(jobs)
    df.to_csv('jobs_data.csv', index=False)
    df.to_json('jobs_data.json', orient='records', indent=2)
    print(f'🎉 Scraped {len(jobs)} jobs! Files saved.')
